search:angular+firebase-performance-opti.content:
- Install Firebase CLI globally using `npm install -g firebase-tools`
- Initialize Firebase in your Angular project with `firebase init`
- Add Firebase Performance Monitoring to your project by installing the AngularFire package:
  ```bash
  npm install @angular/fire@latest firebase@latest --save
  ```
- Import and configure Firebase in your app module:
  ```typescript
  import { provideFirebaseApp, initializeApp } from '@angular/fire/app';
  import { getPerformance } from 'firebase/performance';

  @NgModule({
    providers: [
      provideFirebaseApp(() => initializeApp(environment.firebase)),
      {
        provide: Performance,
        useFactory: () => getPerformance(),
      },
    ],
  })
  export class AppModule {}
  ```
- Ensure your `environment.ts` and `environment.prod.ts` files contain the correct Firebase configuration:
  ```typescript
  export const environment = {
    production: false,
    firebase: {
      apiKey: 'YOUR_API_KEY',
      authDomain: 'YOUR_AUTH_DOMAIN',
      projectId: 'YOUR_PROJECT_ID',
      storageBucket: 'YOUR_STORAGE_BUCKET',
      messagingSenderId: 'YOUR_MESSAGING_SENDER_ID',
      appId: 'YOUR_APP_ID'
    }
  };
  ```
- Use Firebase Performance Monitoring in your services or components:
  ```typescript
  import { Injectable } from '@angular/core';
  import { Performance, trace } from '@angular/fire/performance';

  @Injectable({
    providedIn: 'root'
  })
  export class PerformanceService {
    constructor(private performance: Performance) {}

    startTrace(traceName: string): void {
      const perfTrace = trace(this.performance, traceName);
      perfTrace.start();
      // Perform actions to be traced
      perfTrace.stop();
    }
  }
  ```
- Deploy your Angular app using `ng build --prod` and then deploy it to Firebase Hosting with `firebase deploy`.
